--
-- Table structure for table `biometric_anomalies`
--

DROP TABLE IF EXISTS `biometric_anomalies`;
CREATE TABLE `biometric_anomalies` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `raw_log_id` bigint unsigned DEFAULT NULL,
  `fingerprint_id` int DEFAULT NULL,
  `user_id` bigint unsigned DEFAULT NULL,
  `student_id` bigint unsigned DEFAULT NULL,
  `anomaly_type` varchar(100) COLLATE utf8mb4_general_ci NOT NULL,
  `severity` varchar(20) COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'warning',
  `event_time` datetime DEFAULT NULL,
  `message` text COLLATE utf8mb4_general_ci NOT NULL,
  `details_json` longtext COLLATE utf8mb4_general_ci,
  `status` varchar(20) COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'open',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uniq_biometric_anomaly` (`raw_log_id`,`anomaly_type`),
  KEY `idx_biometric_anomaly_status` (`status`),
  KEY `idx_biometric_anomaly_created` (`created_at`)
) ENGINE=InnoDB AUTO_INCREMENT=2282 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

