--
-- Table structure for table `biometric_audit_logs`
--

DROP TABLE IF EXISTS `biometric_audit_logs`;
CREATE TABLE `biometric_audit_logs` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `actor_user_id` bigint unsigned DEFAULT NULL,
  `actor_role` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `action` varchar(100) COLLATE utf8mb4_general_ci NOT NULL,
  `target_type` varchar(100) COLLATE utf8mb4_general_ci NOT NULL,
  `target_id` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `details_json` longtext COLLATE utf8mb4_general_ci,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_biometric_audit_created` (`created_at`),
  KEY `idx_biometric_audit_action` (`action`)
) ENGINE=InnoDB AUTO_INCREMENT=710 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

