--
-- Table structure for table `biometric_sync_runs`
--

DROP TABLE IF EXISTS `biometric_sync_runs`;
CREATE TABLE `biometric_sync_runs` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `initiated_by_user_id` bigint unsigned DEFAULT NULL,
  `trigger_source` varchar(50) COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'manual',
  `status` varchar(20) COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'running',
  `connector_output` longtext COLLATE utf8mb4_general_ci,
  `import_summary` longtext COLLATE utf8mb4_general_ci,
  `raw_inserted` int NOT NULL DEFAULT '0',
  `processed_logs` int NOT NULL DEFAULT '0',
  `attendance_changed` int NOT NULL DEFAULT '0',
  `anomalies_found` int NOT NULL DEFAULT '0',
  `started_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `finished_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_biometric_sync_started` (`started_at`),
  KEY `idx_biometric_sync_status` (`status`)
) ENGINE=InnoDB AUTO_INCREMENT=684 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

