DROP TABLE IF EXISTS `calendar_events`;
CREATE TABLE `calendar_events` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `user_id` int NOT NULL,
  `title` varchar(255) COLLATE utf8mb4_general_ci NOT NULL,
  `location` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `description` text COLLATE utf8mb4_general_ci,
  `start_at` datetime NOT NULL,
  `end_at` datetime NOT NULL,
  `color` varchar(20) COLLATE utf8mb4_general_ci DEFAULT '#0d6efd',
  `attendance_multiplier` decimal(6,2) DEFAULT NULL,
  `apply_when_not_late` tinyint(1) NOT NULL DEFAULT '0',
  `late_grace_minutes` int DEFAULT NULL,
  `applies_to_weekday` varchar(16) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `is_all_day` tinyint(1) NOT NULL DEFAULT '0',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `deleted_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_calendar_events_user_range` (`user_id`,`start_at`,`end_at`),
  KEY `idx_calendar_events_deleted` (`deleted_at`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


