DROP TABLE IF EXISTS `ojt_partner_companies`;
CREATE TABLE `ojt_partner_companies` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `company_lookup_key` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `company_name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `company_address` text COLLATE utf8mb4_unicode_ci,
  `supervisor_name` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `supervisor_position` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `company_representative` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `company_profile_picture` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `company_representative_position` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uniq_company_lookup` (`company_lookup_key`)
) ENGINE=InnoDB AUTO_INCREMENT=329 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

