--
-- Table structure for table `user_two_factor_codes`
--

DROP TABLE IF EXISTS `user_two_factor_codes`;
CREATE TABLE `user_two_factor_codes` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `user_id` int NOT NULL,
  `purpose` varchar(30) COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'login',
  `code_hash` char(64) COLLATE utf8mb4_general_ci NOT NULL,
  `attempt_count` smallint unsigned NOT NULL DEFAULT '0',
  `ip_address` varchar(45) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `user_agent` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `expires_at` datetime NOT NULL,
  `consumed_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_user_two_factor_lookup` (`user_id`,`purpose`,`consumed_at`,`expires_at`),
  KEY `idx_user_two_factor_created` (`created_at`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


