--
-- View structure for view `attendance_with_student_info`
--

DROP VIEW IF EXISTS `attendance_with_student_info`;
CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`%` SQL SECURITY DEFINER VIEW `attendance_with_student_info` AS select `a`.`id` AS `id`,`a`.`attendance_date` AS `attendance_date`,`s`.`student_id` AS `student_number`,`s`.`first_name` AS `first_name`,`s`.`last_name` AS `last_name`,`s`.`email` AS `email`,`c`.`name` AS `course_name`,`i`.`position` AS `internship_position`,`a`.`morning_time_in` AS `morning_time_in`,`a`.`morning_time_out` AS `morning_time_out`,`a`.`break_time_in` AS `break_time_in`,`a`.`break_time_out` AS `break_time_out`,`a`.`afternoon_time_in` AS `afternoon_time_in`,`a`.`afternoon_time_out` AS `afternoon_time_out`,`a`.`status` AS `status`,`u`.`name` AS `approved_by_name`,`a`.`approved_at` AS `approved_at`,`a`.`remarks` AS `remarks` from ((((`attendances` `a` left join `students` `s` on((`a`.`student_id` = `s`.`id`))) left join `courses` `c` on((`s`.`course_id` = `c`.`id`))) left join `internships` `i` on(((`s`.`id` = `i`.`student_id`) and (`i`.`status` in ('ongoing','completed'))))) left join `users` `u` on((`a`.`approved_by` = `u`.`id`))) order by `a`.`attendance_date` desc;

--
-- View structure for view `pending_attendance_records`
--

DROP VIEW IF EXISTS `pending_attendance_records`;
CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`%` SQL SECURITY DEFINER VIEW `pending_attendance_records` AS select `a`.`id` AS `id`,`a`.`attendance_date` AS `attendance_date`,`s`.`student_id` AS `student_id`,concat(`s`.`first_name`,' ',`s`.`last_name`) AS `student_name`,`c`.`name` AS `course`,`i`.`company_name` AS `internship_company`,`a`.`morning_time_in` AS `morning_time_in`,`a`.`break_time_in` AS `break_time_in`,`a`.`afternoon_time_in` AS `afternoon_time_in`,`a`.`status` AS `status`,`a`.`created_at` AS `created_at` from (((`attendances` `a` join `students` `s` on((`a`.`student_id` = `s`.`id`))) left join `courses` `c` on((`s`.`course_id` = `c`.`id`))) left join `internships` `i` on((`s`.`id` = `i`.`student_id`))) where (`a`.`status` = 'pending') order by `a`.`attendance_date` desc;

--
-- View structure for view `student_attendance_summary`
--

DROP VIEW IF EXISTS `student_attendance_summary`;
CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`%` SQL SECURITY DEFINER VIEW `student_attendance_summary` AS select `s`.`id` AS `id`,`s`.`student_id` AS `student_id`,concat(`s`.`first_name`,' ',`s`.`last_name`) AS `student_name`,count(0) AS `total_attendance_records`,sum((case when (`a`.`status` = 'approved') then 1 else 0 end)) AS `approved_count`,sum((case when (`a`.`status` = 'pending') then 1 else 0 end)) AS `pending_count`,sum((case when (`a`.`status` = 'rejected') then 1 else 0 end)) AS `rejected_count`,round(((sum((case when (`a`.`status` = 'approved') then 1 else 0 end)) / count(0)) * 100),2) AS `approval_percentage` from (`attendances` `a` join `students` `s` on((`a`.`student_id` = `s`.`id`))) group by `s`.`id`;

--
-- View structure for view `student_profile_with_internship`
--

DROP VIEW IF EXISTS `student_profile_with_internship`;
CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`%` SQL SECURITY DEFINER VIEW `student_profile_with_internship` AS select `s`.`id` AS `id`,`s`.`student_id` AS `student_id`,concat(`s`.`first_name`,' ',coalesce(`s`.`middle_name`,''),' ',`s`.`last_name`) AS `full_name`,`s`.`email` AS `email`,`s`.`phone` AS `phone`,`s`.`date_of_birth` AS `date_of_birth`,`s`.`gender` AS `gender`,`s`.`address` AS `address`,`s`.`emergency_contact` AS `emergency_contact`,(case when (`s`.`status` in ('1','active')) then 1 else 0 end) AS `is_active`,`c`.`name` AS `course`,`c`.`code` AS `course_code`,`u`.`name` AS `user_name`,`u`.`role` AS `user_role`,`i`.`id` AS `internship_id`,`i`.`type` AS `internship_type`,`i`.`company_name` AS `company_name`,`i`.`position` AS `position`,`i`.`start_date` AS `start_date`,`i`.`end_date` AS `end_date`,`i`.`status` AS `internship_status`,`i`.`required_hours` AS `required_hours`,`i`.`rendered_hours` AS `rendered_hours`,`i`.`completion_percentage` AS `completion_percentage`,`coord`.`name` AS `coordinator_name`,`sup`.`name` AS `supervisor_name` from (((((`students` `s` left join `courses` `c` on((`s`.`course_id` = `c`.`id`))) left join `users` `u` on((`s`.`user_id` = `u`.`id`))) left join `internships` `i` on((`s`.`id` = `i`.`student_id`))) left join `users` `coord` on((`i`.`coordinator_id` = `coord`.`id`))) left join `users` `sup` on((`i`.`supervisor_id` = `sup`.`id`)));

SET FOREIGN_KEY_CHECKS = 1;


